select count(*) from postgres.comments as c, postgres.posts as p, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b, postgres.users as u where u.id = p.owneruserid and u.id = b.userid and p.id = c.postid and p.id = ph.postid and p.id = v.postid and p.viewcount>=0 and p.answercount>=0 and p.answercount<=7 and p.favoritecount>=0 and p.favoritecount<=17 and v.votetypeid=5 and b."date">=timestamp '2010-08-01 02:54:53' and u.reputation>=1 and u.views>=0 and u.creationdate>=timestamp '2010-08-19 06:26:34' and u.creationdate<=timestamp '2014-09-11 05:22:26';
